VALUES
  ('dietitian-moex-08524', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列有關於醫院團膳供應單位之感染管控與防護措施之敘述，何者錯誤？', '["自助餐業者在配膳台加設防塵罩", "送餐人員及餐車均不進入隔離病房", "工作人員可在隔離區內的傳染區、前室和緩衝區飲食和飲水", "用餐方式以「食不語」、「交錯坐」為原則"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4ba10aa76df7", "answer_pdf_sha1": "07d310bd3799", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08525', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '有關蛋類烹調之注意事項，下列敘述何者錯誤？', '["用於製作蛋皮之蛋液可以加入少許澱粉", "炒蛋時用大火且油量少", "製作煎蛋時用小火且油量少", "製作滑蛋時用油量較多"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4ba10aa76df7", "answer_pdf_sha1": "07d310bd3799", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08526', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '大量團膳製備時，下列有關烹調注意事項的敘述，何者錯誤？', '["降低豆腐入鍋後翻攪次數，易保持其完整性", "剩餘的綠葉菜餚與沾料可以重複使用", "川燙時，水中加油讓川燙後蔬菜外觀油亮", "製作三色蛋時，為了美觀，可以先將皮蛋蒸熟後再加入"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4ba10aa76df7", "answer_pdf_sha1": "07d310bd3799", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08527', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '添加下列何種物質，可以縮短蛋品加熱所需凝固時間？', '["水", "糖", "酒", "鹽"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4ba10aa76df7", "answer_pdf_sha1": "07d310bd3799", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08528', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '蔬菜類食物在烹飪時，遇酸、鹼、熱時其顏色變化，下列敘述何者有誤？', '["菠菜川燙時，葉綠素會溶於水", "白色蔬菜製備時加入少許鹼，色澤會更白", "胡蘿蔔炒蛋時，胡蘿蔔能保有顯明之紅色", "涼拌紅高麗菜加醋，會使菜變鮮紅"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4ba10aa76df7", "answer_pdf_sha1": "07d310bd3799", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08529', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列那一項不是團膳採購作業應遵循之基本原則？', '["廠商地點", "優良品質", "物料類別", "合理價格"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4ba10aa76df7", "answer_pdf_sha1": "07d310bd3799", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08530', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列那一道名菜不屬於台菜？', '["紅蟳米糕", "當歸燉雞", "樟茶鴨", "鹽酥蝦"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4ba10aa76df7", "answer_pdf_sha1": "07d310bd3799", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08531', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '有關電腦化收銀系統POS的敘述，下列何者正確？', '["POS的全名是Personal Operation System", "可以提高前後場的連結效率，但是不能做出點餐品項的刪減", "可以針對每天的營業資料做整合", "可以決定菜單品項的刪減，但是還無法與電腦連結"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08532', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '學校餐廳應如何維護學生飲食的品質？', '["餐廳承包商應該每學年更換，以遴選的競爭促使廠商提供優良的服務", "廚房的設備只可更新不能擴充，以免影響餐廳用餐區的面積", "承包商常與學校對立，所以校方要盡量避免不定期的抽查才能使廠商安心工作", "烹調完成的食物應盡量於三小時內讓學生食用完畢"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08533', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '避免水管管線阻塞成廚房積水，截油槽應設於：', '["前處理區", "烹調區", "配膳區", "餐具洗滌區"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
